import { type VariantProps, cva } from 'class-variance-authority';
import { useState } from 'react';

import { cn } from '../utils/cn';

const avatarVariants = cva(
  'relative flex shrink-0 overflow-hidden rounded-full',
  {
    variants: {
      size: {
        sm: 'h-8 w-8',
        md: 'h-10 w-10',
        lg: 'h-12 w-12',
      },
    },
    defaultVariants: {
      size: 'md',
    },
  }
);

type AvatarProps = React.ComponentProps<'div'> &
  VariantProps<typeof avatarVariants>;

function Avatar({ className, size, children, ...props }: AvatarProps) {
  return (
    <div
      data-slot="avatar"
      className={cn(avatarVariants({ size }), className)}
      {...props}
    >
      {children}
    </div>
  );
}

type AvatarImageProps = React.ComponentProps<'img'> & {
  onLoadError?: () => void;
};

function AvatarImage({
  className,
  onLoadError,
  onError,
  ...props
}: AvatarImageProps) {
  const [hasError, setHasError] = useState(false);

  if (hasError) {
    return null;
  }

  return (
    <img
      data-slot="avatar-image"
      className={cn('aspect-square h-full w-full object-cover', className)}
      onError={(e) => {
        setHasError(true);
        onLoadError?.();
        onError?.(e);
      }}
      {...props}
    />
  );
}

type AvatarFallbackProps = React.ComponentProps<'div'>;

function AvatarFallback({ className, children, ...props }: AvatarFallbackProps) {
  return (
    <div
      data-slot="avatar-fallback"
      className={cn(
        'flex h-full w-full items-center justify-center rounded-full bg-surface text-sm font-medium',
        className
      )}
      {...props}
    >
      {children}
    </div>
  );
}

export { Avatar, AvatarImage, AvatarFallback, avatarVariants };
export type { AvatarProps, AvatarImageProps, AvatarFallbackProps };
